UPDATE exercises SET description = 'Cet exercice apprend à votre chien à monter et à rester calmement les quatre pattes sur un objet stable quand vous le lui demandez. Il devient ainsi plus à l''aise avec de nouvelles surfaces, ce qui est excellent pour sa confiance en lui et pour faciliter des situations quotidiennes comme monter en voiture ou franchir de petits obstacles en promenade. C''est aussi une belle façon de renforcer votre lien et votre complicité.', summary = 'Apprenez à votre chien à monter calmement et à rester sur un objet, renforçant sa confiance et votre lien.', short_instruction = 'Guidez votre chien pour qu''il monte ses quatre pattes sur un objet et récompensez-le quand il y reste.', short_title = '4 pattes sur un objet', objective = 'L''objectif est que votre chien puisse, sur commande vocale, placer ses quatre pattes sur un objet désigné et y rester tranquillement pendant quelques secondes, même en présence de légères distractions. Cela développe sa confiance, son équilibre, et sa capacité à se concentrer sur vous et la tâche demandée.', dedication = 'La constance est la clé du succès', duration = '5 min', repetitions = '5 fois', frequency = '1x/jour', environment = 'tous', success_criteria = 'Votre chien monte sur l''objet avec ses quatre pattes, y reste calmement pendant au moins 15 secondes sur une simple commande vocale (''Sur l''objet''), sans que vous n''ayez besoin de le guider avec la main ou une friandise.', stop_criteria = 'Si votre chien halète excessivement (sauf après un jeu intense), bâille à répétition (signe de stress), se lèche les babines fréquemment, détourne le regard, tremble, a la queue basse ou sous le ventre, ou refuse manifestement de coopérer malgré des encouragements positifs. Ces signes indiquent qu''il est temps de faire une pause ou d''arrêter l''exercice pour aujourd''hui.', validation_protocol = 'L''exercice est validé quand votre chien monte sur l''objet avec ses quatre pattes et y reste pendant au moins 15 secondes, sans aucune aide vocale ni gestuelle de votre part, pendant 3 tentatives consécutives, dans 3 environnements différents (maison, jardin calme, parc avec quelques distractions).', vigilance = 'Vérifiez toujours la stabilité de l''objet avant chaque utilisation. Observez attentivement le langage corporel de votre chien pour déceler le moindre signe de stress ou d''inconfort. Ne laissez jamais votre chien sauter de l''objet sans votre permission, guidez la descente pour éviter les blessures articulaires. Soyez attentif à ne pas créer de la frustration ou de la peur, en allant toujours à son rythme.', age_recommendation = 'tous', intensity_level = 3, cognitive_load = 3, physical_load = 2 WHERE slug = '4-pattes-objet';
UPDATE exercises SET description = 'Cet exercice apprend à votre chien à aboyer quand vous le lui demandez, puis à se taire sur commande. C''est un trick amusant et utile pour canaliser les aboiements, par exemple pour alerter si besoin. Il permet de renforcer votre communication et le contrôle que vous avez sur un comportement naturel.', summary = 'Apprenez à votre chien à aboyer quand vous le demandez et à se taire quand vous le voulez !', short_instruction = 'Provoquez un aboiement, marquez-le avec votre signal, récompensez, puis apprenez-lui le silence.', short_title = 'Aboie sur commande', objective = 'L''objectif est que votre chien aboie sur votre signal verbal ''Aboie !'' et s''arrête sur ''Stop !'', de manière fiable, dans différents environnements et sans aide gestuelle de votre part.', dedication = 'La constance est la clé du succès', duration = '5 min', repetitions = '5 fois', frequency = '1x/jour', environment = 'tous', success_criteria = 'Le chien aboie clairement sur la commande ''Aboie !'' (sans provocation) et arrête d''aboyer dans les 3 secondes suivant la commande ''Stop !'', le tout sans hésitation.', stop_criteria = 'Si le chien halète excessivement, bâille de manière répétée, tourne la tête ou évite votre regard, lèche ses babines fréquemment, a la queue basse ou entre les pattes, ou tremble légèrement. Ce sont des signes de stress ou de fatigue. Il faut alors arrêter immédiatement l''exercice et lui offrir un moment de calme.', validation_protocol = 'L''exercice est validé quand le chien aboie sur la commande ''Aboie !'' (sans provocation) et se tait sur ''Stop !'' (sans aboiement supplémentaire), 5 fois sur 5 tentatives consécutives, dans 3 environnements différents (maison, jardin calme, parc avec quelques distractions). Le silence doit durer au moins 5 secondes avant la relance de la commande.', vigilance = 'Surveillez attentivement les aboiements de réactivité : ne jamais récompenser un aboiement de peur ou d''agression. Assurez-vous que le chien s''amuse et ne ressent aucune pression. Il est facile de basculer d''un aboiement contrôlé à des aboiements intempestifs si l''exercice n''est pas bien géré. Ne pas entraîner l''exercice quand le chien est déjà excité ou sous le coup de l''émotion.', age_recommendation = 'tous', intensity_level = 3, cognitive_load = 3, physical_load = 2 WHERE slug = 'aboie-sur-commande';
UPDATE exercises SET description = 'Cet exercice apprend à votre chien à rester calmement en position couchée, même lorsque vous quittez la pièce.', summary = 'Apprenez à votre chien à rester seul et calme en votre absence.', short_instruction = 'Demandez à votre chien de se coucher, puis quittez la pièce et revenez après un court instant.', short_title = 'Absence couchée', objective = 'Apprendre à votre chien à rester sagement en position couchée sans bouger, même quand vous n''êtes plus visible.', dedication = 'La constance est la clé du succès', duration = '5 min', repetitions = '5 fois', frequency = '1x/jour', environment = 'tous', success_criteria = 'Votre chien reste en position couchée, calme et détendu, pendant au moins une minute sans que vous soyez visible.', stop_criteria = 'Arrêtez si votre chien bâille, se lèche la truffe de manière répétée, halète excessivement ou tremble.', validation_protocol = 'L''exercice est validé quand le chien maintient la position couchée pendant 1 minute hors de vue, 3 fois sur 5.', vigilance = 'Soyez très attentif aux signaux de stress liés à votre absence.', age_recommendation = 'tous', intensity_level = 5, cognitive_load = 5, physical_load = 3 WHERE slug = 'absence-couchee';